import React, { useState } from 'react';
import { 
  Box, 
  Typography, 
  Paper, 
  Button,
  alpha,
  useTheme,
  Dialog,
  IconButton,
  Avatar,
  Tooltip
} from '@mui/material';
import { styled } from '@mui/material/styles';
import { 
  Link as LinkIcon,
  Close,
  Telegram,
  AccountBalanceWallet,
  Security,
  Speed
} from '@mui/icons-material';
import { motion } from 'framer-motion';

// Стилизованные компоненты
const ConnectCard = styled(Paper)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(3),
  boxShadow: '0 8px 32px rgba(0,0,0,0.08)',
  background: `linear-gradient(135deg, ${alpha(theme.palette.primary.main, 0.04)} 0%, ${alpha(theme.palette.primary.light, 0.08)} 100%)`,
  border: `1px solid ${alpha(theme.palette.primary.main, 0.1)}`,
  position: 'relative',
  overflow: 'hidden',
  maxWidth: 400,
  margin: '0 auto'
}));

const WalletHeader = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  marginBottom: theme.spacing(3),
}));

const ConnectButton = styled(Button)(({ theme }) => ({
  borderRadius: theme.spacing(3),
  padding: theme.spacing(1.5, 3),
  fontWeight: 600,
  textTransform: 'none',
  boxShadow: '0 6px 20px rgba(0,0,0,0.08)',
  marginTop: theme.spacing(3),
  '&:hover': {
    boxShadow: '0 8px 25px rgba(0,0,0,0.15)',
    transform: 'translateY(-2px)',
  }
}));

const FeatureItem = styled(Box)(({ theme }) => ({
  display: 'flex',
  alignItems: 'center',
  marginBottom: theme.spacing(2),
}));

const LogoIcon = styled(Box)(({ theme }) => ({
  width: 40,
  height: 40,
  borderRadius: '50%',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  marginRight: theme.spacing(1.5),
  background: theme.palette.primary.main,
  color: theme.palette.common.white,
}));

const BackgroundCircle = styled(Box)(({ theme }) => ({
  position: 'absolute',
  top: '-80px',
  right: '-80px',
  width: '200px',
  height: '200px',
  borderRadius: '50%',
  background: alpha(theme.palette.primary.main, 0.05),
  zIndex: 0,
}));

const BackgroundCircleSmall = styled(Box)(({ theme }) => ({
  position: 'absolute',
  bottom: '-40px',
  left: '10%',
  width: '120px',
  height: '120px',
  borderRadius: '50%',
  background: alpha(theme.palette.primary.main, 0.03),
  zIndex: 0,
}));

const TelegramWalletConnect: React.FC = () => {
  const theme = useTheme();
  const [isOpen, setIsOpen] = useState(false);

  const handleConnectWallet = () => {
    // Здесь будет логика для привязки кошелька Telegram
    console.log('Connecting Telegram wallet...');
    // Обычно здесь будет редирект на страницу авторизации Telegram
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.4 }}
    >
      <ConnectCard>
        <BackgroundCircle />
        <BackgroundCircleSmall />
        
        <WalletHeader>
          <LogoIcon>
            <AccountBalanceWallet sx={{ fontSize: 22 }} />
          </LogoIcon>
          <Typography variant="h5" fontWeight={700}>
            Кошелек
          </Typography>
        </WalletHeader>
        
        <Typography variant="h6" fontWeight={600} sx={{ mb: 1 }}>
          Привяжите кошелек Telegram
        </Typography>
        
        <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
          Подключите ваш кошелек Telegram для быстрых и удобных транзакций внутри нашей системы.
        </Typography>
        
        <Box sx={{ position: 'relative', zIndex: 1 }}>
          <FeatureItem>
            <Avatar sx={{ bgcolor: alpha(theme.palette.primary.main, 0.1), mr: 2 }}>
              <Security sx={{ color: theme.palette.primary.main, fontSize: 20 }} />
            </Avatar>
            <Box>
              <Typography variant="body2" fontWeight={600}>
                Безопасные транзакции
              </Typography>
              <Typography variant="caption" color="text.secondary">
                Защита средств на всех этапах
              </Typography>
            </Box>
          </FeatureItem>
          
          <FeatureItem>
            <Avatar sx={{ bgcolor: alpha(theme.palette.primary.main, 0.1), mr: 2 }}>
              <Speed sx={{ color: theme.palette.primary.main, fontSize: 20 }} />
            </Avatar>
            <Box>
              <Typography variant="body2" fontWeight={600}>
                Мгновенные переводы
              </Typography>
              <Typography variant="caption" color="text.secondary">
                Моментальное пополнение баланса
              </Typography>
            </Box>
          </FeatureItem>
          
          <FeatureItem>
            <Avatar sx={{ bgcolor: alpha(theme.palette.primary.main, 0.1), mr: 2 }}>
              <LinkIcon sx={{ color: theme.palette.primary.main, fontSize: 20 }} />
            </Avatar>
            <Box>
              <Typography variant="body2" fontWeight={600}>
                Единый аккаунт
              </Typography>
              <Typography variant="caption" color="text.secondary">
                Используйте один аккаунт для всех операций
              </Typography>
            </Box>
          </FeatureItem>
        </Box>
        
        <ConnectButton
          fullWidth
          variant="contained"
          color="primary"
          startIcon={<LinkIcon />}
          onClick={handleConnectWallet}
        >
          Привязать кошелек Telegram
        </ConnectButton>
      </ConnectCard>
    </motion.div>
  );
};

export default TelegramWalletConnect;
